/*
 * hypot() test harness — prints (x_hex, y_hex, output_hex) triples.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly hypot  (test_hypot_opt.elf)
 *   2. Linked with toolchain's default hypot       (test_hypot_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifdef EN_PERF
static volatile double g_acc;

static void emit(double x, double y)
{
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    volatile double vy = y;
    g_acc += hypot(vx, vy);
}

static void emit_u(uint64_t bits_x, uint64_t bits_y)
{
    emit(u2d(bits_x), u2d(bits_y));
}
#else
static void emit(double x, double y)
{
    double r = hypot(x, y);
    printf("%016llx %016llx %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u(y),
           (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits_x, uint64_t bits_y)
{
    emit(u2d(bits_x), u2d(bits_y));
}
#endif

/* ------------------------------------------------------------------ */
/* 100 representative test points                                      */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (10) --- */
    emit(0.0, 0.0);
    emit(-0.0, 0.0);
    emit(0.0, -0.0);
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);  /* qNaN, 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);  /* 1.0, qNaN */
    emit_u(0x7ff0000000000001ULL, 0x3ff0000000000000ULL);  /* sNaN, 1.0 */
    emit_u(0xfff8000000000000ULL, 0x3ff0000000000000ULL);  /* -qNaN, 1.0 */
    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL);  /* +Inf, 1.0 */
    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL);  /* -Inf, 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x7ff0000000000000ULL);  /* 1.0, +Inf */

    /* --- Section 2: Subnormal (denormal) values (8) --- */
    emit_u(0x0000000000000001ULL, 0x0000000000000001ULL);  /* min positive subnormal pair */
    emit_u(0x8000000000000001ULL, 0x0000000000000001ULL);  /* min negative subnormal, min positive subnormal */
    emit_u(0x0008000000000000ULL, 0x0008000000000000ULL);  /* mid subnormal pair */
    emit_u(0x8008000000000000ULL, 0x8008000000000000ULL);  /* negative mid subnormal pair */
    emit_u(0x000fffffffffffffULL, 0x000fffffffffffffULL);  /* max subnormal pair */
    emit_u(0x800fffffffffffffULL, 0x000fffffffffffffULL);  /* negative max subnormal, positive max subnormal */
    emit_u(0x0000000000000001ULL, 0x0008000000000000ULL);  /* min subnormal, mid subnormal */
    emit_u(0x0008000000000000ULL, 0x000fffffffffffffULL);  /* mid subnormal, max subnormal */

    /* --- Section 3: Normal boundary values (8) --- */
    emit(DBL_MIN, DBL_MIN);                                /* 2^-1022 pair */
    emit(-DBL_MIN, DBL_MIN);                               /* negative DBL_MIN, positive DBL_MIN */
    emit_u(0x0010000000000001ULL, 0x0010000000000000ULL);  /* one ULP above DBL_MIN, DBL_MIN */
    emit(DBL_MAX, 1.0);                                    /* DBL_MAX with small second arg */
    emit(-DBL_MAX, 1.0);                                   /* negative DBL_MAX with small second arg */
    emit_u(0x7fefffffffffffffULL, 0x7fefffffffffffffULL);  /* DBL_MAX pair -> overflow */
    emit_u(0x7fefffffffffffffULL, 0x0010000000000000ULL);  /* DBL_MAX, DBL_MIN */
    emit_u(0x7feeffffffffffffULL, 0x7fefffffffffffffULL);  /* one ULP below DBL_MAX, DBL_MAX */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3fefffffffffffffULL, 0x3fefffffffffffffULL);  /* one ULP below 1.0 pair */
    emit(1.0, 1.0);
    emit_u(0x3ff0000000000001ULL, 0x3ff0000000000001ULL);  /* one ULP above 1.0 pair */
    emit_u(0x3fefffffffffffffULL, 0x3ff0000000000001ULL);  /* one ULP below 1.0, one ULP above 1.0 */
    emit_u(0x3ff0000000000010ULL, 0x3ff0000000000010ULL);  /* a few ULPs above 1.0 pair */
    emit(-1.0, 1.0);
    emit(-1.0, -1.0);
    emit_u(0xbfefffffffffffffULL, 0x3ff0000000000001ULL);  /* one ULP toward zero from -1.0, one ULP above 1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit(0.5, 0.5);                                        /* 0x3fe0000000000000 pair */
    emit_u(0x3fdfffffffffffffULL, 0x3fe0000000000000ULL);  /* one ULP below 0.5, 0.5 */
    emit_u(0x3fe0000000000001ULL, 0x3fe0000000000001ULL);  /* one ULP above 0.5 pair */
    emit(2.0, 2.0);                                        /* 0x4000000000000000 pair */
    emit_u(0x3fffffffffffffffULL, 0x4000000000000000ULL);  /* one ULP below 2.0, 2.0 */
    emit_u(0x4000000000000001ULL, 0x4000000000000001ULL);  /* one ULP above 2.0 pair */

    /* --- Section 6: Pythagorean triples and known exact results (14) --- */
    emit(3.0, 4.0);    /* 3-4-5 triple: hypot = 5.0 */
    emit(4.0, 3.0);    /* commutative check */
    emit(5.0, 12.0);   /* 5-12-13 triple: hypot = 13.0 */
    emit(12.0, 5.0);
    emit(8.0, 15.0);   /* 8-15-17 triple: hypot = 17.0 */
    emit(7.0, 24.0);   /* 7-24-25 triple: hypot = 25.0 */
    emit(20.0, 21.0);  /* 20-21-29 triple: hypot = 29.0 */
    emit(9.0, 40.0);   /* 9-40-41 triple: hypot = 41.0 */
    emit(1.0, 0.0);    /* degenerate: hypot(1,0) = 1 */
    emit(0.0, 1.0);    /* degenerate: hypot(0,1) = 1 */
    emit(1.0, 1.0);    /* hypot(1,1) = sqrt(2) */
    emit(2.0, 2.0);    /* hypot(2,2) = 2*sqrt(2) */
    emit(3.0, 3.0);    /* hypot(3,3) = 3*sqrt(2) */
    emit(10.0, 10.0);  /* hypot(10,10) = 10*sqrt(2) */

    /* --- Section 7: Large argument overflow/underflow stress (10) --- */
    emit(1.0e10, 1.0e10);
    emit(1.0e100, 1.0e100);
    emit(1.0e150, 1.0e150);
    emit(1.0e200, 1.0e200);
    emit(1.0e300, 1.0e300);    /* result overflows to Inf */
    emit(1.0e-10, 1.0e-10);
    emit(1.0e-100, 1.0e-100);
    emit(1.0e-150, 1.0e-150);
    emit(1.0e-200, 1.0e-200);  /* both inputs tiny subnormal-like range */
    emit(1.0e-300, 1.0e-300);  /* result underflows toward zero */

    /* --- Section 8: Mixed-magnitude (large and small together) (10) --- */
    emit(1.0e10, 1.0);         /* dominated by large arg */
    emit(1.0, 1.0e10);
    emit(1.0e100, 1.0e-100);   /* extreme ratio */
    emit(1.0e-100, 1.0e100);
    emit(DBL_MAX, DBL_MIN);    /* max normal, min normal */
    emit(1.0e154, 1.0e-154);   /* near sqrt(DBL_MAX) scale */
    emit(1.0e15, 1.0e-15);     /* large ratio, both normal */
    emit(1.0e8, 1.0e-8);
    emit(1.0e50, 1.0e-50);
    emit(1.0e200, 1.0e-200);

    /* --- Section 9: Sign symmetry cases (8) --- */
    /* hypot is defined to ignore signs: hypot(x,y) = hypot(-x,y) = hypot(x,-y) */
    emit(-3.0, 4.0);
    emit(3.0, -4.0);
    emit(-3.0, -4.0);
    emit(-5.0, 12.0);
    emit(-1.0e10, 1.0e10);
    emit(1.0e10, -1.0e10);
    emit(-1.0e10, -1.0e10);
    emit(-DBL_MIN, -DBL_MIN);

    /* --- Section 10: ULP neighbors of key outputs and hard rounding cases (18) --- */
    /* ULP neighbors of inputs that produce hypot = 5.0 (3-4-5 triple) */
    emit_u(0x4008000000000000ULL, 0x4010000000000000ULL);  /* 3.0, 4.0 exact */
    emit_u(0x4007ffffffffffffULL, 0x4010000000000000ULL);  /* one ULP below 3.0, 4.0 */
    emit_u(0x4008000000000001ULL, 0x4010000000000000ULL);  /* one ULP above 3.0, 4.0 */
    /* ULP neighbors around sqrt(2) inputs: hypot(1,1) = sqrt(2) */
    emit_u(0x3fefffffffffffffULL, 0x3ff0000000000000ULL);  /* one ULP below 1.0, 1.0 */
    emit_u(0x3ff0000000000001ULL, 0x3ff0000000000000ULL);  /* one ULP above 1.0, 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x3fefffffffffffffULL);  /* 1.0, one ULP below 1.0 */
    /* Hard cases: equal large/small exponent combinations */
    emit_u(0x4340000000000000ULL, 0x4340000000000000ULL);  /* 2^53, 2^53 */
    emit_u(0x3ca0000000000000ULL, 0x3ca0000000000000ULL);  /* 2^-53, 2^-53 */
    emit_u(0x4690000000000000ULL, 0x4690000000000000ULL);  /* 2^106, 2^106 (near overflow for sum-of-squares) */
    emit_u(0x3950000000000000ULL, 0x3950000000000000ULL);  /* 2^-106, 2^-106 (near underflow for sum-of-squares) */
    /* Cases where rescaling logic is exercised */
    emit_u(0x5fe0000000000000ULL, 0x3ff0000000000000ULL);  /* 2^511, 1.0: sum-of-squares overflows before rescale */
    emit_u(0x3ff0000000000000ULL, 0x5fe0000000000000ULL);  /* 1.0, 2^511 */
    emit_u(0x2000000000000000ULL, 0x3ff0000000000000ULL);  /* 2^-511, 1.0: underflow before rescale */
    emit_u(0x3ff0000000000000ULL, 0x2000000000000000ULL);  /* 1.0, 2^-511 */
    /* Asymmetric inputs near exact integer outputs */
    emit(6.0, 8.0);    /* 6-8-10 scaled 3-4-5: hypot = 10.0 */
    emit(9.0, 12.0);   /* 9-12-15 scaled 3-4-5: hypot = 15.0 */
    emit(0.3, 0.4);    /* 0.3-0.4-0.5 scaled 3-4-5: hypot = 0.5 */
    emit(0.6, 0.8);    /* 0.6-0.8-1.0 scaled 3-4-5: hypot = 1.0 */
}

/* 8x8 ULP grid over [1.0, 2.0] x [1.0, 2.0] */
static void test_exhaustive_small(void)
{
    uint64_t start = 0x3ff0000000000000ULL; /* 1.0 */
    uint64_t end = 0x4000000000000000ULL;   /* 2.0 */

    for (uint64_t x = start; x <= end; x += 562949953421312ULL)
        for (uint64_t y = start; y <= end; y += 562949953421312ULL)
            emit_u(x, y);
}

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_exhaustive_small();
#endif
    return 0;
}
